class BankAccount:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount
        print(f"{self.owner} deposited ${amount}. Balance: ${self.balance}")

account = BankAccount("Alice", 100)
account.deposit(50)

